INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Gestion & maîtrise des réseaux sociaux', 'Formation sur l’utilisation des réseaux sociaux pour générer des ventes et fidéliser les clients.', 5, 150000.00, 'entreprise', '2026-10-05', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre l’importance stratégique des réseaux sociaux\n• Maîtriser les principales plateformes sociales pour la vente\n• Développer des stratégies de communication et marketing digital\n• Générer des leads et convertir les prospects\n• Suivre et analyser la performance des actions commerciales\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre l’importance des réseaux sociaux pour le commerce, maîtriser les plateformes sociales, développer des stratégies digitales efficaces, générer des leads et convertir les prospects, et analyser la performance des actions commerciales.\n\n--- PRÉREQUIS ---\nConnaissances de base en marketing digital ou commerce. Une familiarité avec les réseaux sociaux est recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction aux réseaux sociaux dans le commerce\nModule 2 : Définir sa stratégie commerciale\nModule 3 : Création de contenu engageant\nModule 4 : Prospection et génération de leads\nModule 5 : Gestion de la relation client et fidélisation\nModule 6 : Analyse et optimisation des performances\nModule 7 : Atelier final – Plan d’action commercial digital\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommerciaux, responsables marketing, community managers, chefs d’entreprise, entrepreneurs.\n\n--- MÉTHODES ---\nPrésentations interactives, ateliers pratiques, études de cas, simulations de campagnes et exercices analytiques.\n\n--- SUPPORTS ---\nSlides interactives, outils de gestion des réseaux sociaux, CRM, plateformes publicitaires (Facebook Ads, LinkedIn Ads), fiches pratiques et guides stratégiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
